using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9')
        {
            if(ch=='-')f=-1;
            ch=getchar();
        }
        wh(ch>='0'&&ch<='9')
        {
            x=x*10+ch-'0';
            ch=gc();
        }
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)
        {
            pc('-');
            x=-x;
        }
        if(x>9)
        {
            write(x/10);
        }
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
    void writell(ll x)
    {
        write(x);
        pc(' ');
        return;
    }
}
using NP phigrOS;
int n,m,op,x,y;

char k;

string s;

struct segtree
{
	int l,r,cnt[30],tag;
}t[200200];
void build(int p,int l,int r)
{ 
	t[p].l=l,t[p].r=r,t[p].tag=0;
	if(l==r)
    {
		t[p].cnt[s[l-1]-'A'+1]=1;
		return;
	}
	int mid=(l+r)>>1;
	build(p*2,l,mid);
	build(p*2+1,mid+1,r);
	FOR(i,1,26)
    {
		t[p].cnt[i]=t[p*2].cnt[i]+t[p*2+1].cnt[i];
	}
}
void pushdown(int p)
{
	if(t[p].tag)
    {
		t[p*2].cnt[t[p].tag]=t[p*2].r-t[p*2].l+1;
		t[p*2+1].cnt[t[p].tag]=t[p*2+1].r-t[p*2+1].l+1;
		FOR(i,1,26)
        {
			if(i!=t[p].tag)
            {
				t[p*2].cnt[i]=0;
				t[p*2+1].cnt[i]=0;
			}
		}
		t[p*2].tag=t[p].tag;
		t[p*2+1].tag=t[p].tag;
		t[p].tag=0;
	}
}
void change(int p,int l,int r,int c)
{
	if(l>r)
    {
		return ;
	}
	if(l<=t[p].l&&t[p].r<=r)
    {
		t[p].tag=c;
		t[p].cnt[c]=t[p].r-t[p].l+1;
		FOR(i,1,26)
        {
			if(i!=c){
				t[p].cnt[i]=0;
			}
		}
		return ; 
	}
	pushdown(p);
	int mid=(t[p].l+t[p].r)>>1;
	if(l<=mid)
    {
		change(p*2,l,r,c);
	}
	if(r>mid)
    {
		change(p*2+1,l,r,c);
	} 
	FOR(i,1,26)
    {
		t[p].cnt[i]=t[p*2].cnt[i]+t[p*2+1].cnt[i];
	}
}
int ask(int p,int l,int r,int c)
{
	if(l<=t[p].l&&t[p].r<=r)
    {
		return t[p].cnt[c];
	}
	pushdown(p); 
	int mid=(t[p].l+t[p].r)>>1,val=0;
	if(l<=mid)
    {
		val+=ask(p*2,l,r,c);
	}
	if(r>mid)
    {
		val+=ask(p*2+1,l,r,c);
	}
	return val;
}
signed main(void)
{
	cin>>n>>m;
	cin>>s;
	for(int i=0;i<s.size();i++)
    {
		if(s[i]>='a'&&s[i]<='z')
        {
			s[i]=s[i]+'A'-'a';
		}
	}
	build(1,1,n);
	FOR(i,1,m)
    {
		cin>>op;
		if(op==1)
        {
			cin>>x>>y>>k;
			if(k>='a'&&k<='z')
            {
				k=k+'A'-'a';
			}
			cout<<ask(1,x,y,k-'A'+1)<<'\n';
		}
		if(op==2)
        {
			cin>>x>>y>>k;
			if(k>='a'&&k<='z')
            {
				k=k+'A'-'a';
			}
			change(1,x,y,k-'A'+1);
		}

		if(op==3)
        {
			cin>>x>>y;
			int num[30];
			memset(num,0,sizeof num);
			FOR(i,1,26)
            {
				num[i]=num[i-1]+ask(1,x,y,i);
			}
			FOR(i,1,26)
            {
				change(1,x+num[i-1],x+num[i]-1,i);
			}
		}
	}
	return false;
}
